function TodoApp() {
  const [state, dispatch] = React.useReducer(todoReducer, initialState);
  const [input, setInput] = React.useState('');

  const addTodo = () => {
    if (input.trim()) {
      dispatch({ type: 'ADD_TODO', payload: input });
      setInput('');
    }
  };

  return (
    <div style={{ padding: '2rem', maxWidth: '400px' }}>
      <h2>Todo-Liste (useReducer)</h2>
      <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '1rem' }}>
        <input
          value={input}
          onChange={e => setInput(e.target.value)}
          placeholder="Neues Todo..."
          onKeyDown={e => e.key === 'Enter' && addTodo()}
        />
        <button onClick={addTodo}>Hinzufügen</button>
      </div>
      <ul>
        {state.todos.map(todo => (
          <li key={todo.id} style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
            <span
              onClick={() => dispatch({ type: 'TOGGLE_TODO', payload: todo.id })}
              style={{
                textDecoration: todo.done ? 'line-through' : 'none',
                cursor: 'pointer', flex: 1
              }}
            >
              {todo.text}
            </span>
            <button onClick={() => dispatch({ type: 'DELETE_TODO', payload: todo.id })}>
              ❌
            </button>
          </li>
        ))}
      </ul>
      <button onClick={() => dispatch({ type: 'CLEAR_DONE' })}>
        Erledigte löschen
      </button>
    </div>
  );
}

// Simuliere eine teure Berechnung
function expensiveCalculation(limit) {
  console.log('Teure Berechnung läuft...');
  let start = Date.now();
  while (Date.now() - start < 500) {
    // Blockiere für 500ms (simuliert schwere Arbeit)
  }
  return Array.from({ length: limit }, (_, i) => i + 1).filter(n => {
    for (let i = 2; i <= Math.sqrt(n); i++) {
      if (n % i === 0) return false;
    }
    return n > 1;
  });
}

